7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library work;
15	use work.psi_common_math_pkg.all;
16	
17	------------------------------------------------------------------------------
18	-- Package Header
19	------------------------------------------------------------------------------
20	package psi_ms_daq_pkg is
21	
22	  constant MaxStreams_c     : integer := 32;
23	  constant MaxWindows_c     : integer := 32;
24	  constant MaxStreamsBits_c : integer := log2ceil(MaxStreams_c);
25	  constant MaxWindowsBits_c : integer := log2ceil(MaxWindows_c);
26	  constant MaxStreamWidth_c : integer := 64;
