47			signal Clk : in std_logic;
48			signal StrIrq : in std_logic_vector;
49			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
50			signal Dma_Cmd_Vld : in std_logic;
51			constant Generics_c : Generics_t);
