54			signal Clk : in std_logic;
55			signal StrIrq : in std_logic_vector;
56			signal Dma_Resp : inout DaqDma2DaqSm_Resp_t;
57			signal Dma_Resp_Vld : inout std_logic;
58			signal Dma_Resp_Rdy : in std_logic;
