76	package body psi_ms_daq_daq_sm_tb_case_single_simple is
77		procedure control (
78			signal Clk : in std_logic;
79			signal Rst : inout std_logic;
80			signal GlbEna : inout std_logic;
81			signal StrEna : inout std_logic_vector;
82			signal StrIrq : in std_logic_vector;
83			signal Inp_HasLast : inout std_logic_vector;
84			signal Inp_Level : inout t_aslv16;
85			signal Ts_Vld : inout std_logic_vector;
86			signal Ts_Rdy : in std_logic_vector;
87			signal Ts_Data : inout t_aslv64;
88			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
89			signal Dma_Cmd_Vld : in std_logic;
90			constant Generics_c : Generics_t) is
91			variable StartTime_v : time;
92		begin
93			print(">> -- single_simple --");
94			InitTestCase(Clk, Rst);
95			
96			-- Check Steady behavior
97			print(">> Check Steady Behavior");
98			TestCase := 0;
99			StartTime_v := now;
100			while now < StartTime_v + 1 us loop
101				StdlvCompareInt(0, Ts_Rdy, "Ts_Rdy high in steady check");
102				wait until rising_edge(Clk);
103			end loop;
104			ControlWaitCompl(Clk);
105			
106			-- No reaction on insignificant leven
107			print(">> No reaction on insignificant leven");
108			TestCase := 1;
109			StartTime_v := now;
110			while now < StartTime_v + 1 us loop
111				StdlvCompareInt(0, Ts_Rdy, "Ts_Rdy high in steady check");
112				wait until rising_edge(Clk);
113			end loop;
114			ControlWaitCompl(Clk);	
115			
116			-- First transfer after startup, 4k Aligned
117			-- .. This is required to bypass all special handling for the first transfer after enabling a stream.
118			print(">> First transfer after startup, 4k Aligned");	
119			TestCase := 2;
120			for str in 0 to 3 loop
121				Inp_Level(str) <= std_logic_vector(to_unsigned(Size4k_c/DataWidthBytes_c, Inp_Level(str)'length));
122				wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
123				Inp_Level(str) <= (others => '0');	
124				wait for 1 us;
125			end loop;
126			ControlWaitCompl(Clk);
127			
128			-- Check a single 4k aligned burst on stream 1
129			print(">> most simple 4k Aligned transfer");
130			TestCase := 3;
131			Inp_Level(1) <= std_logic_vector(to_unsigned(Size4k_c/DataWidthBytes_c, Inp_Level(0)'length));
132			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
133			Inp_Level(1) <= (others => '0');		
134			ControlWaitCompl(Clk);
135			
136			-- Check two 4k Transfers in a row on stream 0
137			print(">> two 4k Aligned transfers");	
138			TestCase := 4;
139			Inp_Level(0) <= std_logic_vector(to_unsigned(Size4k_c/DataWidthBytes_c, Inp_Level(0)'length));
140			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
141			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
142			Inp_Level(0) <= (others => '0');
143			ControlWaitCompl(Clk);	
144	
145			-- Check maximum Transfer size limitation
146			print(">> Transfer size limitation to 4k");	
147			TestCase := 5;
148			Inp_Level(0) <= std_logic_vector(to_unsigned(Size4k_c*2/DataWidthBytes_c, Inp_Level(0)'length));
149			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
150			Inp_Level(0) <= (others => '0');
151			ControlWaitCompl(Clk);			
152			
153			-- Check 4k boundary limitation
154			print(">> Check 4k boundary limitation");	
155			TestCase := 6;
156			Inp_Level(0) <= std_logic_vector(to_unsigned(Size4k_c/DataWidthBytes_c, Inp_Level(0)'length));
157			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
158			Inp_Level(0) <= (others => '0');
159			ControlWaitCompl(Clk);		
160			
161			-- Check window size limitation
162			print(">> Check window size limitation");	
163			TestCase := 7;
164			Inp_Level(1) <= std_logic_vector(to_unsigned(Size4k_c/DataWidthBytes_c, Inp_Level(0)'length));
165			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
166			Inp_Level(1) <= (others => '0');
167			ControlWaitCompl(Clk);		
168			
169			-- check response smaller than request
170			print(">> check response smaller than request");	
171			TestCase := 8;
172			Inp_Level(1) <= std_logic_vector(to_unsigned(Size4k_c/DataWidthBytes_c, Inp_Level(0)'length));
173			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
174			Inp_Level(1) <= (others => '0');
175			ControlWaitCompl(Clk);	
176			
177			FinishTestCase;
178			
179		end procedure;
