181		procedure dma_cmd (
182			signal Clk : in std_logic;
183			signal StrIrq : in std_logic_vector;
184			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
185			signal Dma_Cmd_Vld : in std_logic;
186			constant Generics_c : Generics_t) is
187			variable StartTime_v : time;
188		begin
