202				StdlCompare(0, Dma_Cmd_Vld, "Dma_Cmd_Vld high in insignificant level");
203				wait until rising_edge(Clk);
204			end loop;
205			ProcDone(2)	:= '1';		
206			
207			-- First transfer after startup, 4k Aligned
208			WaitForCase(2, Clk);
209			for str in 0 to 3 loop
210				ExpectDmaCmd(	Stream	=> str,
211								Address	=> 16#01230000#,
212								MaxSize	=> Size4k_c,
213								Clk		=> Clk,
214								Dma_Cmd	=> Dma_Cmd,
215								Dma_Vld	=> Dma_Cmd_Vld);		
216			end loop;
217			ProcDone(2)	:= '1';	
218			
219			-- Check a single 4k aligned burst on stream 1
220			WaitForCase(3, Clk);
221			ExpectDmaCmd(	Stream	=> 1,
222							Address	=> 16#01238000#,
223							MaxSize	=> Size4k_c,
224							Clk		=> Clk,
225							Dma_Cmd	=> Dma_Cmd,
226							Dma_Vld	=> Dma_Cmd_Vld);			
227			ProcDone(2)	:= '1';	
228			
229			-- Check two 4k Transfers in a row on stream 0
230			WaitForCase(4, Clk);
231			for i in 0 to 1 loop
232				ExpectDmaCmd(	Stream	=> 0,
233								Address	=> 16#01238000# + i*16#1000#,
234								MaxSize	=> Size4k_c,
235								Clk		=> Clk,
236								Dma_Cmd	=> Dma_Cmd,
237								Dma_Vld	=> Dma_Cmd_Vld,
238								Msg		=> "Tf" & to_string(i));	
239			end loop;
240			ProcDone(2)	:= '1';		
241	
242			-- Check maximum Transfer size limitation
243			WaitForCase(5, Clk);
244			ExpectDmaCmd(	Stream	=> 0,
245							Address	=> 16#01238000#,
246							MaxSize	=> Size4k_c,
247							Clk		=> Clk,
248							Dma_Cmd	=> Dma_Cmd,
249							Dma_Vld	=> Dma_Cmd_Vld);			
250			ProcDone(2)	:= '1';	
251			
252			-- Check 4k boundary limitation
253			WaitForCase(6, Clk);
254			ExpectDmaCmd(	Stream	=> 0,
255							Address	=> 16#01238000#+384,
256							MaxSize	=> Size4k_c-384,
257							Clk		=> Clk,
258							Dma_Cmd	=> Dma_Cmd,
259							Dma_Vld	=> Dma_Cmd_Vld);			
260			ProcDone(2)	:= '1';	
261			
262			-- Check window size limitation
263			WaitForCase(7, Clk);
264			ExpectDmaCmd(	Stream	=> 1,
265							Address	=> 16#01230000#,
266							MaxSize	=> 502,
267							Clk		=> Clk,
268							Dma_Cmd	=> Dma_Cmd,
269							Dma_Vld	=> Dma_Cmd_Vld);			
270			ProcDone(2)	:= '1';		
271	
272			-- check response smaller than request
273			WaitForCase(8, Clk);
274			ExpectDmaCmd(	Stream	=> 1,
275							Address	=> 16#01230000#,
276							MaxSize	=> Size4k_c,
277							Clk		=> Clk,
278							Dma_Cmd	=> Dma_Cmd,
279							Dma_Vld	=> Dma_Cmd_Vld);			
280			ProcDone(2)	:= '1';			
281			
282		end procedure;
