284		procedure dma_resp (
285			signal Clk : in std_logic;
286			signal StrIrq : in std_logic_vector;
287			signal Dma_Resp : inout DaqDma2DaqSm_Resp_t;
288			signal Dma_Resp_Vld : inout std_logic;
289			signal Dma_Resp_Rdy : in std_logic;
290			signal TfDone : inout std_logic;
291			signal StrLastWin : in WinType_a(Streams_g-1 downto 0);
292			constant Generics_c : Generics_t) is
293			variable StartTime_v : time;
294		begin
295			-- Check Steady behavior
296			WaitForCase(0, Clk);
297			StartTime_v := now;
298			while now < StartTime_v + 1 us loop
299				StdlCompare(0, Dma_Resp_Rdy, "Dma_Resp_Rdy high in steady check");
300				wait until rising_edge(Clk);
301			end loop;
302			ProcDone(1)	:= '1';
303			
304			-- No reaction on insignificant level
