360							Clk				=> Clk,
361							Dma_Resp		=> Dma_Resp,
362							Dma_Resp_Vld	=> Dma_Resp_Vld,
363							Dma_Resp_Rdy	=> Dma_Resp_Rdy);									
364			ProcDone(1)	:= '1';	
365			
366			-- Check 4k boundary limitation
367			WaitForCase(6, Clk);	
