381							Trigger			=> '0',
382							Clk				=> Clk,
383							Dma_Resp		=> Dma_Resp,
384							Dma_Resp_Vld	=> Dma_Resp_Vld,
385							Dma_Resp_Rdy	=> Dma_Resp_Rdy);									
386			ProcDone(1)	:= '1';		
387	
388			-- check response smaller than request
389			WaitForCase(8, Clk);	
390			ApplyDmaResp(	Stream 			=> 1,
391							Size			=> 500,
392							Trigger			=> '0',
393							Clk				=> Clk,
394							Dma_Resp		=> Dma_Resp,
395							Dma_Resp_Vld	=> Dma_Resp_Vld,
