403			signal CtxStr_Cmd : in ToCtxStr_t;
404			signal CtxStr_Resp : inout FromCtx_t;
405			signal CtxWin_Cmd : in ToCtxWin_t;
406			signal CtxWin_Resp : inout FromCtx_t;
407			constant Generics_c : Generics_t) is
408			variable StartTime_v 	: time;
409			variable PtrStr1_v 		: integer;
410		begin
411			-- Check Steady behavior
412			WaitForCase(0, Clk);
413			StartTime_v := now;
414			while now < StartTime_v + 1 us loop
415				StdlCompare(0, CtxStr_Cmd.WenLo, "CtxStr_Cmd.WenLo high in steady check");
416				StdlCompare(0, CtxStr_Cmd.WenHi, "CtxStr_Cmd.WenHi high in steady check");
417				StdlCompare(0, CtxWin_Cmd.WenLo, "CtxWin_Cmd.WenLo high in steady check");
418				StdlCompare(0, CtxWin_Cmd.WenHi, "CtxWin_Cmd.WenHi high in steady check");
419				wait until rising_edge(Clk);
420			end loop;		
421			ProcDone(0)	:= '1';
422			
423			-- No reaction on insignificant leven
424			WaitForCase(1, Clk);
425			StartTime_v := now;
426			while now < StartTime_v + 1 us loop
427				StdlCompare(0, CtxStr_Cmd.WenLo, "CtxStr_Cmd.WenLo high in insignificant level");
428				StdlCompare(0, CtxStr_Cmd.WenHi, "CtxStr_Cmd.WenHi high in insignificant level");
429				StdlCompare(0, CtxWin_Cmd.WenLo, "CtxWin_Cmd.WenLo high in insignificant level");
430				StdlCompare(0, CtxWin_Cmd.WenHi, "CtxWin_Cmd.WenHi high in insignificant level");
431				wait until rising_edge(Clk);
432			end loop;		
433			ProcDone(0)	:= '1';		
434			
435			-- First transfer after startup, 4k Aligned
436			WaitForCase(2, Clk);
437			for str in 0 to 3 loop
438				PtrStr1_v := 16#01230000#;
439				ExpCtxFullBurst(	Stream				=> str,
440									TfSize				=> Size4k_c,
441									PtrBefore			=> PtrStr1_v,
442									SamplesWinBefore	=> 0,
