444									Clk					=> Clk,
445									CtxStr_Cmd			=> CtxStr_Cmd,
446									CtxStr_Resp			=> CtxStr_Resp,
447									CtxWin_Cmd 			=> CtxWin_Cmd,
448									CtxWin_Resp			=> CtxWin_Resp,
449									Msg					=> "Str" & to_string(str));
450			end loop;
451			ProcDone(0)	:= '1';	
452			
453			-- Check a single 4k aligned burst on stream 1
454			WaitForCase(3, Clk);
455			PtrStr1_v := 16#01238000#;
456			ExpCtxFullBurst(	Stream				=> 1,
457								TfSize				=> Size4k_c,
458								PtrBefore			=> PtrStr1_v,
459								SamplesWinBefore	=> 0,
460								PtrAfter			=> PtrStr1_v,
461								Clk					=> Clk,
462								CtxStr_Cmd			=> CtxStr_Cmd,
463								CtxStr_Resp			=> CtxStr_Resp,
464								CtxWin_Cmd 			=> CtxWin_Cmd,
465								CtxWin_Resp			=> CtxWin_Resp);
466			ProcDone(0)	:= '1';	
467			
468			-- Check two 4k Transfers in a row on stream 0
469			WaitForCase(4, Clk);
470			PtrStr1_v := 16#01238000#;
471			for i in 0 to 1 loop
472				ExpCtxFullBurst(	Stream				=> 0,
473									TfSize				=> Size4k_c,
474									PtrBefore			=> PtrStr1_v,
475									SamplesWinBefore	=> 0,
476									PtrAfter			=> PtrStr1_v,
477									Clk					=> Clk,
478									CtxStr_Cmd			=> CtxStr_Cmd,
479									CtxStr_Resp			=> CtxStr_Resp,
480									CtxWin_Cmd 			=> CtxWin_Cmd,
481									CtxWin_Resp			=> CtxWin_Resp);
482			end loop;
483			ProcDone(0)	:= '1';	
484			
485			-- Check maximum Transfer size limitation
486			WaitForCase(5, Clk);
487			PtrStr1_v := 16#01238000#;
488			ExpCtxFullBurst(	Stream				=> 0,
489								TfSize				=> Size4k_c,
490								PtrBefore			=> PtrStr1_v,
491								SamplesWinBefore	=> 0,
492								PtrAfter			=> PtrStr1_v,
493								Clk					=> Clk,
494								CtxStr_Cmd			=> CtxStr_Cmd,
495								CtxStr_Resp			=> CtxStr_Resp,
496								CtxWin_Cmd 			=> CtxWin_Cmd,
497								CtxWin_Resp			=> CtxWin_Resp);
498			ProcDone(0)	:= '1';	
499	
500			-- Check 4k boundary limitation
501			WaitForCase(6, Clk);
502			PtrStr1_v := 16#01238000#+384;
503			ExpCtxFullBurst(	Stream				=> 0,
504								TfSize				=> Size4k_c-384,
505								PtrBefore			=> PtrStr1_v,
506								SamplesWinBefore	=> 0,
507								PtrAfter			=> PtrStr1_v,
508								Clk					=> Clk,
509								CtxStr_Cmd			=> CtxStr_Cmd,
510								CtxStr_Resp			=> CtxStr_Resp,
511								CtxWin_Cmd 			=> CtxWin_Cmd,
512								CtxWin_Resp			=> CtxWin_Resp);
513			assert PtrStr1_v = 16#01239000# report "###ERROR###: Unexpected pointer value after transfer" severity error;
514			ProcDone(0)	:= '1';	
515	
516			-- Check window size limitation	
517			WaitForCase(7, Clk);
518			PtrStr1_v := 16#01230000#;
519			ExpCtxFullBurst(	Stream				=> 1,
520								BufStart			=> 16#01230000#,
521								TfSize				=> 502,
522								NextWin				=> true,
523								WinSize				=> 502,
524								PtrBefore			=> PtrStr1_v,
525								SamplesWinBefore	=> 0,
526								PtrAfter			=> PtrStr1_v,
527								Clk					=> Clk,
528								CtxStr_Cmd			=> CtxStr_Cmd,
529								CtxStr_Resp			=> CtxStr_Resp,
530								CtxWin_Cmd 			=> CtxWin_Cmd,
531								CtxWin_Resp			=> CtxWin_Resp);
532			ProcDone(0)	:= '1';	
533			
534			-- check response smaller than request
535			WaitForCase(8, Clk);
536			PtrStr1_v := 16#01230000#;
537			ExpCtxFullBurst(	Stream				=> 1,
538								BufStart			=> 16#01230000#,
539								TfSize				=> 500,
540								PtrBefore			=> PtrStr1_v,
541								SamplesWinBefore	=> 0,
542								PtrAfter			=> PtrStr1_v,
543								Clk					=> Clk,
544								CtxStr_Cmd			=> CtxStr_Cmd,
545								CtxStr_Resp			=> CtxStr_Resp,
546								CtxWin_Cmd 			=> CtxWin_Cmd,
547								CtxWin_Resp			=> CtxWin_Resp);
548			assert PtrStr1_v = 16#01230000#+500 report "###ERROR###: Unexpected pointer value after transfer" severity error;
549			ProcDone(0)	:= '1';			
